import{_ as t,H as r,f as l,i as e}from"./chunks/framework.eFU6Tutu.js";const b=JSON.parse('{"title":"Базилик","description":"","frontmatter":{},"headers":[],"relativePath":"plants/basil.md","filePath":"plants/basil.md"}'),i={name:"plants/basil.md"};function n(o,a,d,h,s,u){return r(),l("div",null,[...a[0]||(a[0]=[e('<h1 id="базилик" tabindex="-1">Базилик <a class="header-anchor" href="#базилик" aria-label="Permalink to &quot;Базилик&quot;">​</a></h1><p>Базилик — пряное растение с ярким ароматом и пикантным вкусом, которое прекрасно растёт на подоконнике круглый год. Листья используют в свежем и сушёном виде, добавляют в салаты, соусы, мясные блюда и напитки.</p><h2 id="описание" tabindex="-1">Описание <a class="header-anchor" href="#описание" aria-label="Permalink to &quot;Описание&quot;">​</a></h2><p>Базилик — однолетнее травянистое растение высотой 30–60 см. Стебель четырёхгранный, ветвистый. Листья продолговатые или яйцевидные, от ярко-зелёных до тёмно-фиолетовых, в зависимости от сорта. Цветёт мелкими белыми, розовыми или фиолетовыми цветками, собранными в кисть. Аромат обусловлен эфирными маслами, концентрация которых максимальна перед цветением.</p><h2 id="популярные-сорта-для-дома" tabindex="-1">Популярные сорта для дома <a class="header-anchor" href="#популярные-сорта-для-дома" aria-label="Permalink to &quot;Популярные сорта для дома&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Сорт</th><th>Особенности</th></tr></thead><tbody><tr><td><strong>Базилик душистый (обыкновенный)</strong></td><td>Зелёные листья, классический аромат, идеален для итальянской кухни</td></tr><tr><td><strong>Базилик фиолетовый (ереванский)</strong></td><td>Фиолетовые листья, более острый вкус, подходит к мясным блюдам</td></tr><tr><td><strong>Базилик лимонный</strong></td><td>Светло-зелёные листья, аромат лимона, хорош для чая и рыбы</td></tr><tr><td><strong>Базилик коричный</strong></td><td>Зелёные листья с фиолетовыми прожилками, запах корицы, для десертов</td></tr><tr><td><strong>Базилик тайский</strong></td><td>Фиолетовые стебли и цветы, пряный вкус, для азиатских блюд</td></tr></tbody></table><h2 id="уход" tabindex="-1">Уход <a class="header-anchor" href="#уход" aria-label="Permalink to &quot;Уход&quot;">​</a></h2><p>Выращивание микрозелени — особый, сверхбыстрый процесс, но общие принципы схожи с уходом за другой зеленью. Подробнее читайте в <a href="/care/greens/#базилик">гайде по уходу за зеленью</a>.</p><h2 id="как-использовать-в-еде" tabindex="-1">Как использовать в еде <a class="header-anchor" href="#как-использовать-в-еде" aria-label="Permalink to &quot;Как использовать в еде&quot;">​</a></h2><ul><li>Песто (классический соус)</li><li>Пицца Маргарита</li><li>Паста с томатами и базиликом</li><li>Томатный суп с базиликом</li><li>Базиликовый лимонад</li><li>Добавлять в салаты из помидоров и моцареллы (капрезе)</li></ul><h2 id="полезные-своиства" tabindex="-1">Полезные свойства <a class="header-anchor" href="#полезные-своиства" aria-label="Permalink to &quot;Полезные свойства&quot;">​</a></h2><ul><li>Содержит витамины А, С, К и группы В</li><li>Обладает антибактериальным действием</li><li>Улучшает пищеварение и аппетит</li><li>Снижает уровень стресса и тревожности</li><li>Полезен для кожи и заживления ран</li></ul><h2 id="источники-информации" tabindex="-1">Источники информации <a class="header-anchor" href="#источники-информации" aria-label="Permalink to &quot;Источники информации&quot;">​</a></h2><ul><li><a href="https://ru.ruwiki.ru/wiki/%D0%91%D0%B0%D0%B7%D0%B8%D0%BB%D0%B8%D0%BA" target="_blank" rel="noreferrer">РуВики - Базилик</a></li><li><a href="https://www.greeninfo.ru/basil_growing.html" target="_blank" rel="noreferrer">Базилик: выращивание на подоконнике</a></li></ul><h2 id="похожие-растения" tabindex="-1">Похожие растения <a class="header-anchor" href="#похожие-растения" aria-label="Permalink to &quot;Похожие растения&quot;">​</a></h2><ul><li><a href="/plants/mint.html">Мята</a></li><li><a href="/plants/parsley.html">Петрушка</a></li><li><a href="/plants/dill.html">Укроп</a></li></ul>',16)])])}const f=t(i,[["render",n]]);export{b as __pageData,f as default};
